import pandas as pd
import json
from datetime import datetime

# Get the data from storage
opportunity_data = var_functions.query_db:16

# Convert to DataFrame
if opportunity_data:
    df = pd.DataFrame(opportunity_data)
    print('Loaded data count:', len(df))
    print('Columns:', list(df.columns))

    # Calculate turnaround time for each opportunity
    turnaround_times = []
    for _, row in df.iterrows():
        try:
            created = datetime.fromisoformat(row['CreatedDate'].replace('Z', '+00:00'))
            signed = datetime.strptime(row['CompanySignedDate'], '%Y-%m-%d')
            days = (signed - created).days
            turnaround_times.append({
                'OpportunityId': row['OpportunityId'],
                'OwnerId': row['OwnerId'],
                'TurnaroundDays': days
            })
        except Exception as e:
            print(f'Error processing row: {e}')

    result_df = pd.DataFrame(turnaround_times)
    if not result_df.empty:
        # Calculate average turnaround per agent
        avg_turnaround = result_df.groupby('OwnerId')['TurnaroundDays'].mean().reset_index()
        avg_turnaround = avg_turnaround.sort_values('TurnaroundDays')

        # Find the agent with the quickest average turnaround
        fastest_agent = avg_turnaround.iloc[0]
        result = {'AgentId': fastest_agent['OwnerId'], 'AvgTurnaroundDays': fastest_agent['TurnaroundDays']}
    else:
        result = {'error': 'No valid turnaround data found'}
else:
    result = {'error': 'No data loaded'}

print('__RESULT__:')
print(json.dumps(result))

